mapper.sql:
d.space_id = #{spaceId}
AND (d.visibility = 'SHARED' OR d.user_id = #{userId})

    AND d.deleted_at IS NOT NULL
    AND d.deleted_at IS NULL

AND d.date >= #{startDate}
AND d.date <= #{endDate}

    AND d.locked = 0
    AND (d.title LIKE CONCAT('%', #{keyword}, '%') OR d.content LIKE CONCAT('%', #{keyword}, '%'))

mapper.select:
SELECT 
FROM diary d
INNER JOIN user u ON u.user_id = d.user_id
WHERE d.deleted_at IS NOT NULL AND d.deleted_at < #{cutoff}
ORDER BY d.deleted_at ASC
LIMIT #{limit}
